// ── b3Ɛq WHT Schedule Generator ─────────────────────────────
// NTA 2025 · WHT Regulations 2024
// Groups supplier payments by WHT code and generates Form A schedule

const WHT_RATES = {
  'NG-WHT-DIV': { rate: 0.10, label: 'Dividends' },
  'NG-WHT-INT': { rate: 0.10, label: 'Interest' },
  'NG-WHT-RNT': { rate: 0.10, label: 'Rent' },
  'NG-WHT-ROY': { rate: 0.10, label: 'Royalties' },
  'NG-WHT-DIR': { rate: 0.10, label: 'Director Fees' },
  'NG-WHT-PRF': { rate: 0.10, label: 'Professional Fees' },
  'NG-WHT-TEC': { rate: 0.10, label: 'Technical/Management/Consulting' },
  'NG-WHT-COM': { rate: 0.10, label: 'Commissions' },
  'NG-WHT-SUP': { rate: 0.05, label: 'Contracts & Supply' },
  'NG-WHT-CON': { rate: 0.025, label: 'Construction/Drilling/Survey' },
};

const invoices = $input.all()[0]?.json || [];
const period = new Date();
period.setMonth(period.getMonth() - 1);
const periodLabel = period.toLocaleString('en-NG', { month: 'long', year: 'numeric' });

const fmt = n => '₦' + parseFloat(n).toLocaleString('en-NG', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

// Group by WHT type (using supplier category as proxy)
// In production: use invoice extrafields or supplier WHT code tag
const schedule = {};
let totalGross = 0;
let totalWHT = 0;

if (Array.isArray(invoices)) {
  for (const inv of invoices) {
    // Default: use contracts/supply rate for non-categorised suppliers
    const whtCode = inv.array_options?.options_wht_code || 'NG-WHT-SUP';
    const whtInfo = WHT_RATES[whtCode] || WHT_RATES['NG-WHT-SUP'];
    const gross   = parseFloat(inv.total_ttc || inv.total_ht || 0);
    const wht     = parseFloat((gross * whtInfo.rate).toFixed(2));
    const net     = parseFloat((gross - wht).toFixed(2));

    if (!schedule[whtCode]) {
      schedule[whtCode] = {
        code: whtCode, label: whtInfo.label,
        rate: whtInfo.rate, vendors: [],
        total_gross: 0, total_wht: 0, total_net: 0
      };
    }

    schedule[whtCode].vendors.push({
      vendor_name: inv.socid_name || inv.name || 'Unknown',
      invoice_ref: inv.ref,
      invoice_date: inv.date,
      gross, wht, net,
      tin: inv.array_options?.options_vendor_tin || 'NOT PROVIDED'
    });

    schedule[whtCode].total_gross += gross;
    schedule[whtCode].total_wht   += wht;
    schedule[whtCode].total_net   += net;
    totalGross += gross;
    totalWHT   += wht;
  }
}

const scheduleArr = Object.values(schedule);

// Build summary text
const lines = [
  `📋 *b3Ɛq WHT Schedule — ${periodLabel}*`,
  ``,
  `Total Supplier Payments: ${fmt(totalGross)}`,
  `Total WHT Deducted:      ${fmt(totalWHT)}`,
  `Net Paid to Vendors:     ${fmt(totalGross - totalWHT)}`,
  ``,
  `--- By Transaction Type ---`,
];

for (const s of scheduleArr) {
  lines.push(`• ${s.label} (${(s.rate*100).toFixed(1)}%): ${fmt(s.total_wht)} WHT on ${fmt(s.total_gross)} gross`);
}

lines.push('');
lines.push('⏰ Remit by 21st — file Form A schedule on TaxPro Max');
lines.push('📎 WHT Regulations 2024 · NTA 2025');

return [{
  json: {
    period:        periodLabel,
    total_gross:   totalGross,
    total_wht:     totalWHT,
    total_net:     totalGross - totalWHT,
    schedule:      scheduleArr,
    invoice_count: Array.isArray(invoices) ? invoices.length : 0,
    summary_text:  lines.join('\n'),
    csv_rows: scheduleArr.flatMap(s => s.vendors.map(v => ({
      period:          periodLabel,
      wht_type:        s.label,
      wht_code:        s.code,
      wht_rate:        (s.rate * 100).toFixed(1) + '%',
      vendor_name:     v.vendor_name,
      vendor_tin:      v.tin,
      invoice_ref:     v.invoice_ref,
      invoice_date:    v.invoice_date,
      gross_amount:    v.gross.toFixed(2),
      wht_deducted:    v.wht.toFixed(2),
      net_paid:        v.net.toFixed(2),
    })))
  }
}];

// Convert schedule to CSV (Form A format)
const rows = $input.all()[0].json.csv_rows || [];
if (rows.length === 0) return [{ json: { csv: '', empty: true } }];

const headers = Object.keys(rows[0]);
const csvLines = [
  headers.join(','),
  ...rows.map(row => headers.map(h => `"${String(row[h] || '').replace(/"/g, '""')}"`).join(','))
];

return [{ json: { csv: csvLines.join('\n'), row_count: rows.length } }];
